import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';

@Component({
  selector: 'app-account-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './account-detail.component.html',
  styleUrl: './account-detail.component.css',
})
export class AccountDetailComponent {
  id: string;
  tabs = ['overview', 'contacts', 'projects', 'quotes', 'revenue', 'health', 'channel'];
  activeTab = signal('overview');

  account = computed(() => this.seed.accountById(this.id));
  contacts = computed(() => this.seed.contactsForAccount(this.id));
  projects = computed(() => this.seed.projectsForAccount(this.id));

  quotes = computed(() => {
    const acc = this.account();
    if (!acc) return [];
    const token = acc.name.split(/[\s—-]+/)[0].toLowerCase();
    return this.seed.quotes().filter((q) => q.accountName.toLowerCase().includes(token));
  });

  // revenue bar scaling: backlog vs ytd
  revenueMax = computed(() => {
    const a = this.account();
    return Math.max(1, a?.backlogValue ?? 0, a?.ytdRevenue ?? 0);
  });
  backlogPct = computed(() => Math.round(((this.account()?.backlogValue ?? 0) / this.revenueMax()) * 100));
  ytdPct = computed(() => Math.round(((this.account()?.ytdRevenue ?? 0) / this.revenueMax()) * 100));

  channelParts = computed(() => {
    const raw = this.account()?.channel ?? '';
    return raw.split('→').map((p) => p.trim()).filter((p) => !!p);
  });

  healthBadge(level: string | undefined): string {
    switch (level) {
      case 'strong': return 'badge-success';
      case 'developing': return 'badge-warning';
      case 'at-risk': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  strengthBadge(strength: string): string {
    switch (strength) {
      case 'strong': return 'badge-success';
      case 'developing': return 'badge-warning';
      case 'new': return 'badge-info';
      default: return 'badge-neutral';
    }
  }

  stageBadge(stage: string): string {
    switch (stage) {
      case 'awarded': return 'badge-success';
      case 'closed': return 'badge-neutral';
      case 'negotiation': return 'badge-info';
      case 'submitted': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    const t = this.route.snapshot.queryParamMap.get('tab');
    this.activeTab.set(t && this.tabs.includes(t) ? t : 'overview');
    this.route.queryParamMap.subscribe((q) => {
      const tab = q.get('tab');
      this.activeTab.set(tab && this.tabs.includes(tab) ? tab : 'overview');
    });
  }
}
